import{_ as a,o as i,c as o,a2 as n}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Manual de Domain-Driven Design","description":"","frontmatter":{},"headers":[],"relativePath":"full-stack/arquitectura/ddd/01-introduccion-a-ddd.md","filePath":"full-stack/arquitectura/ddd/01-introduccion-a-ddd.md","lastUpdated":1782521464000}'),l={name:"full-stack/arquitectura/ddd/01-introduccion-a-ddd.md"};function s(t,e,d,r,c,u){return i(),o("div",null,[...e[0]||(e[0]=[n(`<h1 id="manual-de-domain-driven-design" tabindex="-1">Manual de Domain-Driven Design <a class="header-anchor" href="#manual-de-domain-driven-design" aria-label="Permalink to &quot;Manual de Domain-Driven Design&quot;">​</a></h1><p>Domain-Driven Design, o DDD, es una forma de disenar software alrededor del conocimiento del negocio. Su objetivo principal no es aplicar patrones, sino conseguir que el codigo hable el mismo idioma que el dominio que representa.</p><p>DDD aporta mas valor cuando el problema tiene reglas, excepciones, vocabulario propio y decisiones que no se entienden solo mirando tablas o pantallas.</p><h2 id="capitulos-previstos" tabindex="-1">Capitulos previstos <a class="header-anchor" href="#capitulos-previstos" aria-label="Permalink to &quot;Capitulos previstos&quot;">​</a></h2><ol><li><a href="./01-introduccion-a-ddd">Introduccion a DDD</a></li><li><a href="./02-lenguaje-ubicuo">Lenguaje ubicuo</a></li><li><a href="./03-entidades-value-objects-y-agregados">Entidades value objects y agregados</a></li><li><a href="./04-repositorios-servicios-y-eventos">Repositorios servicios y eventos</a></li><li><a href="./05-bounded-contexts">Bounded contexts</a></li><li><a href="./06-integracion-entre-contextos">Integracion entre contextos</a></li><li><a href="./07-buenas-practicas">Buenas practicas</a></li><li><a href="./08-modelado-estrategico">Modelado estrategico</a></li><li><a href="./09-eventos-de-dominio">Eventos de dominio</a></li><li><a href="./10-ddd-tactico-en-backend">DDD tactico en backend</a></li><li><a href="./11-testing-del-dominio">Testing del dominio</a></li><li><a href="./12-proyecto-final">Proyecto final</a></li></ol><h2 id="por-que-existe-ddd" tabindex="-1">Por que existe DDD <a class="header-anchor" href="#por-que-existe-ddd" aria-label="Permalink to &quot;Por que existe DDD&quot;">​</a></h2><p>En muchos proyectos el codigo acaba reflejando tecnologia, no negocio:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>controllers/</span></span>
<span class="line"><span>services/</span></span>
<span class="line"><span>repositories/</span></span>
<span class="line"><span>models/</span></span></code></pre></div><p>Eso puede funcionar, pero no siempre explica conceptos como:</p><ul><li>Pedido confirmado.</li><li>Factura vencida.</li><li>Cliente con riesgo.</li><li>Cupo agotado.</li><li>Matricula cancelable.</li><li>Producto reservable.</li></ul><p>DDD intenta que esos conceptos vivan en el modelo y no solo en conversaciones, tickets o documentacion externa.</p><h2 id="dos-niveles-de-ddd" tabindex="-1">Dos niveles de DDD <a class="header-anchor" href="#dos-niveles-de-ddd" aria-label="Permalink to &quot;Dos niveles de DDD&quot;">​</a></h2><h3 id="ddd-estrategico" tabindex="-1">DDD estrategico <a class="header-anchor" href="#ddd-estrategico" aria-label="Permalink to &quot;DDD estrategico&quot;">​</a></h3><p>Ayuda a dividir el sistema:</p><ul><li>Subdominios.</li><li>Bounded contexts.</li><li>Context maps.</li><li>Relaciones entre equipos y modelos.</li></ul><h3 id="ddd-tactico" tabindex="-1">DDD tactico <a class="header-anchor" href="#ddd-tactico" aria-label="Permalink to &quot;DDD tactico&quot;">​</a></h3><p>Ayuda a disenar el modelo interno:</p><ul><li>Entidades.</li><li>Value objects.</li><li>Agregados.</li><li>Repositorios.</li><li>Servicios de dominio.</li><li>Eventos de dominio.</li></ul><h2 id="cuando-usar-ddd" tabindex="-1">Cuando usar DDD <a class="header-anchor" href="#cuando-usar-ddd" aria-label="Permalink to &quot;Cuando usar DDD&quot;">​</a></h2><ul><li>El negocio tiene reglas complejas.</li><li>Hay muchas excepciones.</li><li>Distintas areas usan palabras diferentes.</li><li>El sistema va a crecer durante anos.</li><li>Los errores de interpretacion son caros.</li></ul><h2 id="cuando-no-compensa" tabindex="-1">Cuando no compensa <a class="header-anchor" href="#cuando-no-compensa" aria-label="Permalink to &quot;Cuando no compensa&quot;">​</a></h2><ul><li>CRUDs simples.</li><li>Prototipos rapidos.</li><li>Scripts internos.</li><li>Aplicaciones donde la logica vive casi toda en otra plataforma.</li></ul><h2 id="idea-central" tabindex="-1">Idea central <a class="header-anchor" href="#idea-central" aria-label="Permalink to &quot;Idea central&quot;">​</a></h2><p>DDD no empieza en el codigo. Empieza entendiendo el dominio con personas que lo conocen y llevando ese lenguaje al diseno del sistema.</p>`,24)])])}const m=a(l,[["render",s]]);export{h as __pageData,m as default};
